mapper.update:
UPDATE sys_role
SET deleted = #{deleted},
    updated_at = NOW(),
    updated_by = #{updatedBy}
WHERE id = #{id}

mapper.select:
SELECT FROM sys_role
deleted = 0
AND role_name LIKE CONCAT('%', #{roleName}, '%')
AND status = #{status}
ORDER BY created_at DESC LIMIT #{limit} OFFSET #{offset}
